    setKey(prev => prev + 1);
  }, []);

  const onReloadWindow = useCallback(<T = Element, E = MouseEvent>(e?: React.MouseEvent<T, E>) => {
    window.location.reload();
    e?.preventDefault();
  }, []);

  return { loading, onLoading, key, onReload, onReloadWindow };
