  useWindowEvent("wheel", handleStop, {
    passive: true
  });

  useWindowEvent("touchmove", handleStop, {
    passive: true
  });

  // cleanup requestAnimationFrame
  useEffect(() => cancel, []);

  return {
    scrollableRef,
    targetRef,
    scrollIntoView,
    cancel
  } as ScrollIntoViewReturnType<Target, Parent>;
