    this.lifeTime = lifeTime;
    this.gravity = { ...gravity };
    this.friction = 0.98;
    this.particles = Array.from({ length: maxParticles }, () => {
      return new Particle({
        position: {
          x: Math.random() * window.innerWidth,
          y: -Math.random() * 80
