      }
      & p a {
        @apply text-blue-600;
      }
      & ol,
      & ul,
      & menu {
        @apply text-muted-foreground marker:text-color;
      }
      & table {
        & tr {
          @apply border-b-border;
          & th {
            @apply bg-muted/60;
          }
          & td {
            @apply text-muted-foreground;
          }
        }
        & thead {
          &::after {
            @apply bg-muted;
          }
          & tr {
            @apply border-b-muted;
          }
        }
        & tbody {
          & tr {
            &:hover,
            &:hover th,
            &:hover td {
              @apply bg-muted/30;
            }
          }
        }
      }
    }

    & h1 {
      @apply scroll-m-20 text-[calc(var(--fz-h1)*var(--prose-heading-scale))] leading-[calc(clamp(2rem,1rem+4vw,4.25rem)*var(--prose-heading-scale))] font-extrabold tracking-tight;
    }
    & h2 {
      @apply scroll-m-20 text-[calc(var(--fz-h2)*var(--prose-heading-scale))] font-bold tracking-tight pb-2 first:mt-0;
    }
    & h3 {
      @apply scroll-m-20 text-[calc(var(--fz-h3)*var(--prose-heading-scale))] leading-9 font-bold tracking-normal;
    }
